&lt;h1 style=&quot;font-family: Arial, sans-serif; color: rgb(51, 51, 51); line-height: 1.2; margin-top: 20px; text-align: center;&quot;&gt;&lt;img style=&quot;max-width: 100%; float: left;&quot; src=&quot;https://i.imgur.com/b9m4CJj.jpeg&quot; alt=&quot;&quot; width=&quot;92&quot;&gt;&lt;/h1&gt;
&lt;h1 style=&quot;font-family: Arial, sans-serif; color: rgb(51, 51, 51); line-height: 1.2; margin-top: 20px; text-align: center;&quot;&gt;&amp;nbsp;&lt;/h1&gt;
&lt;h1 style=&quot;font-family: Arial, sans-serif; color: rgb(51, 51, 51); line-height: 1.2; margin-top: 20px; text-align: center;&quot;&gt;&amp;nbsp;&lt;/h1&gt;
